1	//! The global data and participant for garbage collection.
2	//!
3	//! # Registration
4	//!
5	//! In order to track all participants in one place, we need some form of participant
6	//! registration. When a participant is created, it is registered to a global lock-free
7	//! singly-linked list of registries; and when a participant is leaving, it is unregistered from the
8	//! list.
9	//!
10	//! # Pinning
11	//!
12	//! Every participant contains an integer that tells whether the participant is pinned and if so,
13	//! what was the global epoch at the time it was pinned. Participants also hold a pin counter that
14	//! aids in periodic global epoch advancement.
15	//!
16	//! When a participant is pinned, a `Guard` is returned as a witness that the participant is pinned.
17	//! Guards are necessary for performing atomic operations, and for freeing/dropping locations.
18	//!
19	//! # Thread-local bag
20	//!
21	//! Objects that get unlinked from concurrent data structures must be stashed away until the global
22	//! epoch sufficiently advances so that they become safe for destruction. Pointers to such objects
23	//! are pushed into a thread-local bag, and when it becomes full, the bag is marked with the current
24	//! global epoch and pushed into the global queue of bags. We store objects in thread-local storages
25	//! for amortizing the synchronization cost of pushing the garbages to a global queue.
26	//!
27	//! # Global queue
28	//!
29	//! Whenever a bag is pushed into a queue, the objects in some bags in the queue are collected and
30	//! destroyed along the way. This design reduces contention on data structures. The global queue
31	//! cannot be explicitly accessed: the only way to interact with it is by calling functions
32	//! `defer()` that adds an object to the thread-local bag, or `collect()` that manually triggers
33	//! garbage collection.
34	//!
35	//! Ideally each instance of concurrent data structure may have its own queue that gets fully
36	//! destroyed as soon as the data structure gets dropped.
37	
38	use core::{
39	    cell::Cell,
40	    fmt,
41	    mem::{self, ManuallyDrop},
42	    num::Wrapping,
43	    ptr,
44	};
45	
46	use crossbeam_utils::CachePadded;
47	
48	use crate::{
49	    atomic::{Owned, Shared},
50	    collector::{Collector, LocalHandle},
51	    deferred::Deferred,
52	    epoch::{AtomicEpoch, Epoch},
53	    guard::{Guard, unprotected},
54	    primitive::{
55	        cell::UnsafeCell,
56	        sync::atomic::{self, Ordering},
57	    },
58	    sync::{
59	        list::{Entry, IsElement, IterError, List},
60	        queue::Queue,
61	    },
62	};
63	
64	/// Maximum number of objects a bag can contain.
65	#[cfg(not(any(crossbeam_sanitize, miri)))]
66	const MAX_OBJECTS: usize = 64;
67	// Makes it more likely to trigger any potential data races.
68	#[cfg(any(crossbeam_sanitize, miri))]
69	const MAX_OBJECTS: usize = 4;
70	
71	/// A bag of deferred functions.
72	pub(crate) struct Bag {
73	    /// Stashed objects.
74	    deferreds: [Deferred; MAX_OBJECTS],
75	    len: usize,
76	}
77	
78	/// `Bag::try_push()` requires that it is safe for another thread to execute the given functions.
79	unsafe impl Send for Bag {}
80	
81	impl Bag {
82	    /// Returns a new, empty bag.
83	    pub(crate) fn new() -> Self {
84	        Self::default()
85	    }
86	
87	    /// Returns `true` if the bag is empty.
88	    pub(crate) fn is_empty(&self) -> bool {
89	        self.len == 0
90	    }
91	
92	    /// Attempts to insert a deferred function into the bag.
93	    ///
94	    /// Returns `Ok(())` if successful, and `Err(deferred)` for the given `deferred` if the bag is
95	    /// full.
96	    ///
97	    /// # Safety
98	    ///
99	    /// It should be safe for another thread to execute the given function.
100	    pub(crate) unsafe fn try_push(&mut self, deferred: Deferred) -> Result<(), Deferred> {
101	        if self.len < MAX_OBJECTS {
102	            self.deferreds[self.len] = deferred;
103	            self.len += 1;
104	            Ok(())
105	        } else {
106	            Err(deferred)
107	        }
108	    }
109	
110	    /// Seals the bag with the given epoch.
111	    fn seal(self, epoch: Epoch) -> SealedBag {
112	        SealedBag { epoch, _bag: self }
113	    }
114	}
115	
116	impl Default for Bag {
117	    fn default() -> Self {
118	        Self {
119	            len: 0,
120	            deferreds: [Deferred::NO_OP; MAX_OBJECTS],
121	        }
122	    }
123	}
124	
125	impl Drop for Bag {
126	    fn drop(&mut self) {
127	        // Call all deferred functions.
128	        for deferred in &mut self.deferreds[..self.len] {
129	            let no_op = Deferred::NO_OP;
130	            let owned_deferred = mem::replace(deferred, no_op);
131	            owned_deferred.call();
132	        }
133	    }
134	}
135	
136	// can't #[derive(Debug)] because Debug is not implemented for arrays 64 items long
137	impl fmt::Debug for Bag {
138	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
139	        f.debug_struct("Bag")
140	            .field("deferreds", &&self.deferreds[..self.len])
141	            .finish()
142	    }
143	}
144	
145	/// A pair of an epoch and a bag.
146	#[derive(Default, Debug)]
147	struct SealedBag {
148	    epoch: Epoch,
149	    _bag: Bag,
150	}
151	
152	/// It is safe to share `SealedBag` because `is_expired` only inspects the epoch.
153	unsafe impl Sync for SealedBag {}
154	
155	impl SealedBag {
156	    /// Checks if it is safe to drop the bag w.r.t. the given global epoch.
157	    fn is_expired(&self, global_epoch: Epoch) -> bool {
158	        // A pinned participant can witness at most one epoch advancement. Therefore, any bag that
159	        // is within one epoch of the current one cannot be destroyed yet.
160	        global_epoch.wrapping_sub(self.epoch) >= 2
161	    }
162	}
163	
164	/// The global data for a garbage collector.
165	pub(crate) struct Global {
166	    /// The intrusive linked list of `Local`s.
167	    locals: List<Local>,
168	
169	    /// The global queue of bags of deferred functions.
170	    queue: Queue<SealedBag>,
171	
172	    /// The global epoch.
173	    pub(crate) epoch: CachePadded<AtomicEpoch>,
174	}
175	
176	impl Global {
177	    /// Number of bags to destroy.
178	    const COLLECT_STEPS: usize = 8;
179	
180	    /// Creates a new global data for garbage collection.
181	    #[inline]
182	    pub(crate) fn new() -> Self {
183	        Self {
184	            locals: List::new(),
185	            queue: Queue::new(),
186	            epoch: CachePadded::new(AtomicEpoch::new(Epoch::starting())),
187	        }
188	    }
189	
190	    /// Pushes the bag into the global queue and replaces the bag with a new empty bag.
191	    pub(crate) fn push_bag(&self, bag: &mut Bag, guard: &Guard) {
192	        let bag = mem::replace(bag, Bag::new());
193	
194	        atomic::fence(Ordering::SeqCst);
195	
196	        let epoch = self.epoch.load(Ordering::Relaxed);
197	        self.queue.push(bag.seal(epoch), guard);
198	    }
199	
200	    /// Collects several bags from the global queue and executes deferred functions in them.
201	    ///
202	    /// Note: This may itself produce garbage and in turn allocate new bags.
203	    ///
204	    /// `pin()` rarely calls `collect()`, so we want the compiler to place that call on a cold
205	    /// path. In other words, we want the compiler to optimize branching for the case when
206	    /// `collect()` is not called.
207	    #[cold]
208	    pub(crate) fn collect(&self, guard: &Guard) {
209	        let global_epoch = self.try_advance(guard);
210	
211	        let steps = if cfg!(crossbeam_sanitize) {
212	            usize::MAX
213	        } else {
214	            Self::COLLECT_STEPS
215	        };
216	
217	        for _ in 0..steps {
218	            match self.queue.try_pop_if(
219	                |sealed_bag: &SealedBag| sealed_bag.is_expired(global_epoch),
220	                guard,
221	            ) {
222	                None => break,
223	                Some(sealed_bag) => drop(sealed_bag),
224	            }
225	        }
226	    }
227	
228	    /// Attempts to advance the global epoch.
229	    ///
230	    /// The global epoch can advance only if all currently pinned participants have been pinned in
231	    /// the current epoch.
232	    ///
233	    /// Returns the current global epoch.
234	    ///
235	    /// `try_advance()` is annotated `#[cold]` because it is rarely called.
236	    #[cold]
237	    pub(crate) fn try_advance(&self, guard: &Guard) -> Epoch {
238	        let global_epoch = self.epoch.load(Ordering::Relaxed);
239	        atomic::fence(Ordering::SeqCst);
240	
241	        // For ThreadSanitizer that does not understand fences, we simulate the equivalent effect.
242	        // It is unfortunate that allocation is required, but without it, synchronization might
243	        // occur in cases where it should not, potentially causing false positives.
244	        #[cfg(crossbeam_sanitize_thread)]
245	        let mut locals = alloc::vec![];
246	        // TODO(stjepang): `Local`s are stored in a linked list because linked lists are fairly
247	        // easy to implement in a lock-free manner. However, traversal can be slow due to cache
248	        // misses and data dependencies. We should experiment with other data structures as well.
249	        for local in self.locals.iter(guard) {
250	            match local {
251	                Err(IterError::Stalled) => {
252	                    // A concurrent thread stalled this iteration. That thread might also try to
253	                    // advance the epoch, in which case we leave the job to it. Otherwise, the
254	                    // epoch will not be advanced.
255	                    return global_epoch;
256	                }
257	                Ok(local) => {
258	                    let local_epoch = local.epoch.load(Ordering::Relaxed);
259	
260	                    // If the participant was pinned in a different epoch, we cannot advance the
261	                    // global epoch just yet.
262	                    if local_epoch.is_pinned() && local_epoch.unpinned() != global_epoch {
263	                        return global_epoch;
264	                    }
265	
266	                    #[cfg(crossbeam_sanitize_thread)]
267	                    locals.push(local);
268	                }
269	            }
270	        }
271	        #[cfg(crossbeam_sanitize_thread)]
272	        for local in locals {
273	            local.epoch.load(Ordering::Acquire);
274	        }
275	        #[cfg(not(crossbeam_sanitize_thread))]
276	        atomic::fence(Ordering::Acquire);
277	
278	        // All pinned participants were pinned in the current global epoch.
279	        // Now let's advance the global epoch...
280	        //
281	        // Note that if another thread already advanced it before us, this store will simply
282	        // overwrite the global epoch with the same value. This is true because `try_advance` was
283	        // called from a thread that was pinned in `global_epoch`, and the global epoch cannot be
284	        // advanced two steps ahead of it.
285	        let new_epoch = global_epoch.successor();
286	        self.epoch.store(new_epoch, Ordering::Release);
287	        new_epoch
288	    }
289	}
290	
291	/// Participant for garbage collection.
292	#[repr(C)] // Note: `entry` must be the first field
293	pub(crate) struct Local {
294	    /// A node in the intrusive linked list of `Local`s.
295	    entry: Entry,
296	
297	    /// A reference to the global data.
298	    ///
299	    /// When all guards and handles get dropped, this reference is destroyed.
300	    collector: UnsafeCell<ManuallyDrop<Collector>>,
301	
302	    /// The local bag of deferred functions.
303	    pub(crate) bag: UnsafeCell<Bag>,
304	
305	    /// The number of guards keeping this participant pinned.
306	    guard_count: Cell<usize>,
307	
308	    /// The number of active handles.
309	    handle_count: Cell<usize>,
310	
311	    /// Total number of pinnings performed.
312	    ///
313	    /// This is just an auxiliary counter that sometimes kicks off collection.
314	    pin_count: Cell<Wrapping<usize>>,
315	
316	    /// The local epoch.
317	    epoch: CachePadded<AtomicEpoch>,
318	}
319	
320	// Make sure `Local` is less than or equal to 2048 bytes.
321	// https://github.com/crossbeam-rs/crossbeam/issues/551
322	#[cfg(not(any(crossbeam_sanitize, miri)))] // `crossbeam_sanitize` and `miri` reduce the size of `Local`
323	#[test]
324	fn local_size() {
325	    // TODO: https://github.com/crossbeam-rs/crossbeam/issues/869
326	    // assert!(
327	    //     core::mem::size_of::<Local>() <= 2048,
328	    //     "An allocation of `Local` should be <= 2048 bytes."
329	    // );
330	}
331	
332	impl Local {
333	    /// Number of pinnings after which a participant will execute some deferred functions from the
334	    /// global queue.
335	    const PINNINGS_BETWEEN_COLLECT: usize = 128;
336	
337	    /// Registers a new `Local` in the provided `Global`.
338	    pub(crate) fn register(collector: &Collector) -> LocalHandle {
339	        unsafe {
340	            // Since we dereference no pointers in this block, it is safe to use `unprotected`.
341	
342	            let local = Owned::new(Self {
343	                entry: Entry::default(),
344	                collector: UnsafeCell::new(ManuallyDrop::new(collector.clone())),
345	                bag: UnsafeCell::new(Bag::new()),
346	                guard_count: Cell::new(0),
347	                handle_count: Cell::new(1),
348	                pin_count: Cell::new(Wrapping(0)),
349	                epoch: CachePadded::new(AtomicEpoch::new(Epoch::starting())),
350	            })
351	            .into_shared(unprotected());
352	            collector.global.locals.insert(local, unprotected());
353	            LocalHandle {
354	                local: local.as_raw(),
355	            }
356	        }
357	    }
358	
359	    /// Returns a reference to the `Global` in which this `Local` resides.
360	    #[inline]
361	    pub(crate) fn global(&self) -> &Global {
362	        &self.collector().global
363	    }
364	
365	    /// Returns a reference to the `Collector` in which this `Local` resides.
366	    #[inline]
367	    pub(crate) fn collector(&self) -> &Collector {
368	        self.collector.with(|c| unsafe { &**c })
369	    }
370	
371	    /// Returns `true` if the current participant is pinned.
372	    #[inline]
373	    pub(crate) fn is_pinned(&self) -> bool {
374	        self.guard_count.get() > 0
375	    }
376	
377	    /// Adds `deferred` to the thread-local bag.
378	    ///
379	    /// # Safety
380	    ///
381	    /// It should be safe for another thread to execute the given function.
382	    pub(crate) unsafe fn defer(&self, mut deferred: Deferred, guard: &Guard) {
383	        let bag = self.bag.with_mut(|b| unsafe { &mut *b });
384	
385	        while let Err(d) = unsafe { bag.try_push(deferred) } {
386	            self.global().push_bag(bag, guard);
387	            deferred = d;
388	        }
389	    }
390	
391	    pub(crate) fn flush(&self, guard: &Guard) {
392	        let bag = self.bag.with_mut(|b| unsafe { &mut *b });
393	
394	        if !bag.is_empty() {
395	            self.global().push_bag(bag, guard);
396	        }
397	
398	        self.global().collect(guard);
399	    }
400	
401	    /// Pins the `Local`.
402	    #[inline]
403	    pub(crate) fn pin(&self) -> Guard {
404	        let guard = Guard { local: self };
405	
406	        let guard_count = self.guard_count.get();
407	        self.guard_count.set(guard_count.checked_add(1).unwrap());
408	
409	        if guard_count == 0 {
410	            let global_epoch = self.global().epoch.load(Ordering::Relaxed);
411	            let new_epoch = global_epoch.pinned();
412	
413	            // Now we must store `new_epoch` into `self.epoch` and execute a `SeqCst` fence.
414	            // The fence makes sure that any future loads from `Atomic`s will not happen before
415	            // this store.
416	            if cfg!(all(
417	                any(target_arch = "x86", target_arch = "x86_64"),
418	                not(miri)
419	            )) {
420	                // HACK(stjepang): On x86 architectures there are two different ways of executing
421	                // a `SeqCst` fence.
422	                //
423	                // 1. `atomic::fence(SeqCst)`, which compiles into a `mfence` instruction.
424	                // 2. `_.compare_exchange(_, _, SeqCst, SeqCst)`, which compiles into a `lock cmpxchg`
425	                //    instruction.
426	                //
427	                // Both instructions have the effect of a full barrier, but benchmarks have shown
428	                // that the second one makes pinning faster in this particular case.  It is not
429	                // clear that this is permitted by the C++ memory model (SC fences work very
430	                // differently from SC accesses), but experimental evidence suggests that this
431	                // works fine.  Using inline assembly would be a viable (and correct) alternative,
432	                // but alas, that is not possible on stable Rust.
433	                let current = Epoch::starting();
434	                let res = self.epoch.compare_exchange(
435	                    current,
436	                    new_epoch,
437	                    Ordering::SeqCst,
438	                    Ordering::SeqCst,
439	                );
440	                debug_assert!(res.is_ok(), "participant was expected to be unpinned");
441	                // We add a compiler fence to make it less likely for LLVM to do something wrong
442	                // here.  Formally, this is not enough to get rid of data races; practically,
443	                // it should go a long way.
444	                atomic::compiler_fence(Ordering::SeqCst);
445	            } else {
446	                self.epoch.store(new_epoch, Ordering::Relaxed);
447	                atomic::fence(Ordering::SeqCst);
448	            }
449	
450	            // Increment the pin counter.
451	            let count = self.pin_count.get();
452	            self.pin_count.set(count + Wrapping(1));
453	
454	            // After every `PINNINGS_BETWEEN_COLLECT` try advancing the epoch and collecting
455	            // some garbage.
456	            if count.0 % Self::PINNINGS_BETWEEN_COLLECT == 0 {
457	                self.global().collect(&guard);
458	            }
459	        }
460	
461	        guard
462	    }
463	
464	    /// Unpins the `Local`.
465	    #[inline]
466	    pub(crate) fn unpin(&self) {
467	        let guard_count = self.guard_count.get();
468	        self.guard_count.set(guard_count - 1);
469	
470	        if guard_count == 1 {
471	            self.epoch.store(Epoch::starting(), Ordering::Release);
472	
473	            if self.handle_count.get() == 0 {
474	                unsafe {
475	                    Self::finalize(self);
476	                }
477	            }
478	        }
479	    }
480	
481	    /// Unpins and then pins the `Local`.
482	    #[inline]
483	    pub(crate) fn repin(&self) {
484	        let guard_count = self.guard_count.get();
485	
486	        // Update the local epoch only if there's only one guard.
487	        if guard_count == 1 {
488	            let epoch = self.epoch.load(Ordering::Relaxed);
489	            let global_epoch = self.global().epoch.load(Ordering::Relaxed).pinned();
490	
491	            // Update the local epoch only if the global epoch is greater than the local epoch.
492	            if epoch != global_epoch {
493	                // We store the new epoch with `Release` because we need to ensure any memory
494	                // accesses from the previous epoch do not leak into the new one.
495	                self.epoch.store(global_epoch, Ordering::Release);
496	
497	                // However, we don't need a following `SeqCst` fence, because it is safe for memory
498	                // accesses from the new epoch to be executed before updating the local epoch. At
499	                // worse, other threads will see the new epoch late and delay GC slightly.
500	            }
501	        }
502	    }
503	
504	    /// Increments the handle count.
505	    #[inline]
506	    pub(crate) fn acquire_handle(&self) {
507	        let handle_count = self.handle_count.get();
508	        debug_assert!(handle_count >= 1);
509	        self.handle_count.set(handle_count + 1);
510	    }
511	
512	    /// Decrements the handle count.
513	    #[inline]
514	    pub(crate) unsafe fn release_handle(this: *const Self) {
515	        let guard_count = unsafe { (*this).guard_count.get() };
516	        let handle_count = unsafe { (*this).handle_count.get() };
517	        debug_assert!(handle_count >= 1);
518	        unsafe {
519	            (*this).handle_count.set(handle_count - 1);
520	        }
521	
522	        if guard_count == 0 && handle_count == 1 {
523	            unsafe {
524	                Self::finalize(this);
525	            }
526	        }
527	    }
528	
529	    /// Removes the `Local` from the global linked list.
530	    #[cold]
531	    unsafe fn finalize(this: *const Self) {
532	        unsafe {
533	            debug_assert_eq!((*this).guard_count.get(), 0);
534	            debug_assert_eq!((*this).handle_count.get(), 0);
535	        }
536	
537	        // Temporarily increment handle count. This is required so that the following call to `pin`
538	        // doesn't call `finalize` again.
539	        unsafe {
540	            (*this).handle_count.set(1);
541	        }
542	        unsafe {
543	            // Pin and move the local bag into the global queue. It's important that `push_bag`
544	            // doesn't defer destruction on any new garbage.
545	            let guard = &(*this).pin();
546	            (*this)
547	                .global()
548	                .push_bag((*this).bag.with_mut(|b| &mut *b), guard);
549	        }
550	        // Revert the handle count back to zero.
551	        unsafe {
552	            (*this).handle_count.set(0);
553	        }
554	
555	        unsafe {
556	            // Take the reference to the `Global` out of this `Local`. Since we're not protected
557	            // by a guard at this time, it's crucial that the reference is read before marking the
558	            // `Local` as deleted.
559	            let collector: Collector = ptr::read((*this).collector.with(|c| &*(*c)));
560	
561	            // Mark this node in the linked list as deleted.
562	            (*this).entry.delete(unprotected());
563	
564	            // Finally, drop the reference to the global. Note that this might be the last reference
565	            // to the `Global`. If so, the global data will be destroyed and all deferred functions
566	            // in its queue will be executed.
567	            drop(collector);
568	        }
569	    }
570	}
571	
572	impl IsElement<Self> for Local {
573	    fn entry_of(local: *const Self) -> *const Entry {
574	        // SAFETY: `Local` is `repr(C)` and `entry` is the first field of it.
575	        local.cast::<Entry>()
576	    }
577	
578	    unsafe fn element_of(entry: *const Entry) -> *const Self {
579	        // SAFETY: `Local` is `repr(C)` and `entry` is the first field of it.
580	        entry.cast::<Self>()
581	    }
582	
583	    unsafe fn finalize(entry: *const Entry, guard: &Guard) {
584	        unsafe { guard.defer_destroy(Shared::from(Self::element_of(entry))) }
585	    }
586	}
